/* Technical documentation download card */
.doc-download-card {
  display: grid;
  gap: 10px;
  padding: 14px 15px;
  border: 1px solid rgba(11, 92, 171, 0.26);
  border-radius: 16px;
  background: linear-gradient(180deg, rgba(234, 245, 255, 0.96), rgba(216, 236, 255, 0.92));
  color: #113e68;
}

.doc-download-card strong {
  color: #0b5cab;
}

.doc-download-card .footnote {
  color: #35536f;
}

.doc-download-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: fit-content;
  min-height: 38px;
  padding: 0 15px;
  border-radius: 999px;
  background: linear-gradient(135deg, #0b5cab, #1478c8);
  color: #ffffff !important;
  font-weight: 820;
  font-size: 13px;
  text-decoration: none;
  box-shadow: 0 12px 28px rgba(11, 92, 171, 0.22);
  transition: transform 0.16s ease, box-shadow 0.16s ease;
}

.doc-download-link:hover {
  transform: translateY(-2px);
  box-shadow: 0 18px 38px rgba(11, 92, 171, 0.30);
}

.doc-download-link:active {
  transform: translateY(0) scale(0.99);
}
